import React, { useEffect, useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { perfAPI, employeesAPI, aiAgentsAPI } from '../services/api';
import {
  PageHeader, Card, Table, Btn, Modal, Input, Textarea, Select, Badge, Tabs,
  StarRating, toast,
} from '../components/ui';
import { Plus, Star, Send } from 'lucide-react';

const STATUS_MAP = {
  draft:        { variant: 'neutral', label: 'Draft' },
  submitted:    { variant: 'info',    label: 'Submitted' },
  hod_reviewed: { variant: 'blue',   label: 'HOD Reviewed' },
  finalized:    { variant: 'success', label: 'Finalized' },
};

export default function Performance() {
  const { hasRole } = useAuth();
  const [tab, setTab] = useState('my');
  const [cycles, setCycles] = useState([]);
  const [myGoals, setMyGoals] = useState([]);
  const [hodGoals, setHodGoals] = useState([]);
  const [allGoals, setAllGoals] = useState([]);
  const [loading, setLoading] = useState(true);

  const [showCreate, setShowCreate] = useState(false);
  const [showSelf, setShowSelf] = useState(null);
  const [showHOD, setShowHOD] = useState(null);
  const [showFinalize, setShowFinalize] = useState(null);

  const [showCreateCycle, setShowCreateCycle] = useState(false);
  const [cycleForm, setCycleForm] = useState({ title: '', year: new Date().getFullYear(), start_date: '', end_date: '' });
  const [showAssignGoal, setShowAssignGoal] = useState(false);
  const [assignForm, setAssignForm] = useState({ employee_id: '', cycle_id: '', goals_text: '' });
  const [teamMembers, setTeamMembers] = useState([]);

  // Bug #6 fix: changed from {title, description} to {goals_text} to match GoalCreate schema
  const [goalForm, setGoalForm] = useState({ cycle_id: '', goals_text: '' });
  const [selfRating, setSelfRating] = useState(0);
  const [selfComments, setSelfComments] = useState('');
  const [hodRating, setHodRating] = useState(0);
  const [hodComments, setHodComments] = useState('');
  const [finRating, setFinRating] = useState(0);
  const [finComments, setFinComments] = useState('');
  const [submitting, setSubmitting] = useState(false);

  const [aiLoading, setAiLoading] = useState(false);
  const [aiSuggestion, setAiSuggestion] = useState('');

  const isHR = hasRole('hr');
  const isHOD = hasRole('department_head');

  const tabs = [
    { key: 'my', label: 'My Goals' },
    ...(isHOD ? [{ key: 'hod', label: 'HOD Review' }] : []),
    ...(isHR ? [{ key: 'all', label: 'All Goals' }] : []),
  ];

  const loadData = async () => {
    setLoading(true);
    try {
      try {
        const { data } = await perfAPI.cycles();
        setCycles(data);
      } catch { setCycles([]); }

      try {
        const { data } = await perfAPI.myGoals();
        setMyGoals(data);
      } catch { setMyGoals([]); }

      if (isHOD) {
        try {
          const { data } = await perfAPI.hodPending();
          setHodGoals(data);
          const { data: emps } = await employeesAPI.list();
          setTeamMembers(emps || []);
        } catch { setHodGoals([]); setTeamMembers([]); }
      }

      if (isHR) {
        try {
          const { data } = await perfAPI.allGoals({});
          setAllGoals(data);
        } catch { setAllGoals([]); }
      }
    } catch (e) {
      toast(e.response?.data?.detail || 'Failed to load performance data', 'error');
    } finally {
      setLoading(false);
    }
  };

  // eslint-disable-next-line react-hooks/exhaustive-deps
  useEffect(() => { loadData(); }, []);

  // Bug #6 fix: send goals_text instead of title/description
  const handleCreateGoal = async (e) => {
    e.preventDefault();
    setSubmitting(true);
    try {
      await perfAPI.submitGoals({
        cycle_id: parseInt(goalForm.cycle_id),
        goals_text: goalForm.goals_text,
      });
      toast('Goal created!', 'success');
      setShowCreate(false);
      setGoalForm({ cycle_id: '', goals_text: '' });
      loadData();
    } catch (e) {
      toast(e.response?.data?.detail || 'Failed to create goal', 'error');
    } finally {
      setSubmitting(false);
    }
  };

  const handleSubmitGoal = async (id) => {
    try {
      await perfAPI.submitGoal(id);
      toast('Goal submitted for review', 'success');
      loadData();
    } catch (e) {
      toast(e.response?.data?.detail || 'Failed to submit goal', 'error');
    }
  };

  const handleAssignGoal = async (e) => {
    e.preventDefault();
    setSubmitting(true);
    try {
      await perfAPI.assignGoal({
        employee_id: parseInt(assignForm.employee_id),
        cycle_id: parseInt(assignForm.cycle_id),
        goals_text: assignForm.goals_text,
      });
      toast('Goal assigned successfully!', 'success');
      setShowAssignGoal(false);
      setAssignForm({ employee_id: '', cycle_id: '', goals_text: '' });
      loadData();
    } catch (e) {
      toast(e.response?.data?.detail || 'Failed to assign goal', 'error');
    } finally {
      setSubmitting(false);
    }
  };

  const handleEnhanceGoal = async () => {
    if (!goalForm.goals_text) {
      toast('Please write a goal description first', 'warning');
      return;
    }
    setAiLoading(true);
    setAiSuggestion('');
    try {
      const { data } = await aiAgentsAPI.suggestGoals({ goals_text: goalForm.goals_text });
      setAiSuggestion(data.result);
    } catch (e) {
      toast(e.response?.data?.detail || 'Failed to enhance goal', 'error');
    } finally {
      setAiLoading(false);
    }
  };

  const handleCreateCycle = async (e) => {
    e.preventDefault();
    setSubmitting(true);
    try {
      await perfAPI.createCycle(cycleForm);
      toast('Appraisal cycle created!', 'success');
      setShowCreateCycle(false);
      setCycleForm({ title: '', year: new Date().getFullYear(), start_date: '', end_date: '' });
      loadData();
    } catch (e) {
      toast(e.response?.data?.detail || 'Failed to create cycle', 'error');
    } finally {
      setSubmitting(false);
    }
  };

  const handleCloseCycle = async (id) => {
    try {
      await perfAPI.closeCycle(id);
      toast('Cycle closed successfully', 'success');
      loadData();
    } catch (e) {
      toast(e.response?.data?.detail || 'Failed to close cycle', 'error');
    }
  };

  // Bug #7 fix: self_comment → self_comments
  const handleSelfReview = async (e) => {
    e.preventDefault();
    if (!selfRating || selfRating < 1 || selfRating > 5) {
      toast('Rating must be between 1 and 5', 'error');
      return;
    }
    setSubmitting(true);
    try {
      await perfAPI.selfRate(showSelf.id, {
        self_rating: selfRating,
        self_comments: selfComments,
      });
      toast('Self review submitted', 'success');
      setShowSelf(null);
      loadData();
    } catch (e) {
      toast(e.response?.data?.detail || 'Failed to submit self review', 'error');
    } finally {
      setSubmitting(false);
    }
  };

  // Bug #8 fix: hod_comment → hod_comments
  const handleHODReview = async (e) => {
    e.preventDefault();
    if (!hodRating || hodRating < 1 || hodRating > 5) {
      toast('Rating must be between 1 and 5', 'error');
      return;
    }
    setSubmitting(true);
    try {
      await perfAPI.hodReview(showHOD.id, {
        hod_rating: hodRating,
        hod_comments: hodComments,
      });
      toast('HOD review submitted', 'success');
      setShowHOD(null);
      loadData();
    } catch (e) {
      toast(e.response?.data?.detail || 'Failed to submit review', 'error');
    } finally {
      setSubmitting(false);
    }
  };

  // Bug #9 fix: hr_comment → hr_comments
  const handleFinalize = async (e) => {
    e.preventDefault();
    if (!finRating || finRating < 1 || finRating > 5) {
      toast('Rating must be between 1 and 5', 'error');
      return;
    }
    setSubmitting(true);
    try {
      await perfAPI.hrFinalize(showFinalize.id, {
        final_rating: finRating,
        hr_comments: finComments,
      });
      toast('Goal finalized', 'success');
      setShowFinalize(null);
      loadData();
    } catch (e) {
      toast(e.response?.data?.detail || 'Failed to finalize', 'error');
    } finally {
      setSubmitting(false);
    }
  };

  const renderStars = (val) => (
    <StarRating value={val || 0} readOnly size={16} />
  );

  // Bug #18 fix: r.title/r.description → r.goals_text
  const myCols = [
    { key: 'goals_text', label: 'Goal', render: (r) => (
      <div>
        <div style={{ fontWeight: 500, maxWidth: 300 }} className="truncate">{r.goals_text || '—'}</div>
      </div>
    )},
    { key: 'status', label: 'Status', render: (r) => {
      const s = STATUS_MAP[r.status] || STATUS_MAP.draft;
      return <Badge variant={s.variant}>{s.label}</Badge>;
    }},
    { key: 'self_rating', label: 'Self', render: (r) => renderStars(r.self_rating) },
    { key: 'hod_rating', label: 'HOD', render: (r) => renderStars(r.hod_rating) },
    { key: 'final_rating', label: 'Final', render: (r) => renderStars(r.final_rating) },
    { key: 'actions', label: '', render: (r) => (
      <div style={{ display: 'flex', gap: 6 }}>
        {r.status === 'draft' && (
          <Btn variant="outline" size="xs" onClick={() => handleSubmitGoal(r.id)}>
            <Send size={13} /> Submit
          </Btn>
        )}
        {r.status === 'submitted' && !r.self_rating && (
          <Btn variant="secondary" size="xs" onClick={() => {
            setShowSelf(r);
            setSelfRating(r.self_rating || 0);
            setSelfComments(r.self_comments || '');
          }}>
            <Star size={13} /> Self Review
          </Btn>
        )}
      </div>
    )},
  ];

  const hodCols = [
    { key: 'employee_id', label: 'Emp ID' },
    { key: 'goals_text', label: 'Goal', render: (r) => (
      <span style={{ maxWidth: 250 }} className="truncate">{r.goals_text || '—'}</span>
    )},
    { key: 'self_rating', label: 'Self Rating', render: (r) => renderStars(r.self_rating) },
    { key: 'actions', label: '', render: (r) => (
      <Btn variant="primary" size="xs" onClick={() => {
        setShowHOD(r);
        setHodRating(r.hod_rating || 0);
        setHodComments(r.hod_comments || '');
      }}>
        <Star size={13} /> Review
      </Btn>
    )},
  ];

  const allCols = [
    { key: 'employee_id', label: 'Emp ID' },
    { key: 'goals_text', label: 'Goal', render: (r) => (
      <span style={{ maxWidth: 200 }} className="truncate">{r.goals_text || '—'}</span>
    )},
    { key: 'status', label: 'Status', render: (r) => {
      const s = STATUS_MAP[r.status] || STATUS_MAP.draft;
      return <Badge variant={s.variant}>{s.label}</Badge>;
    }},
    { key: 'self_rating', label: 'Self', render: (r) => renderStars(r.self_rating) },
    { key: 'hod_rating', label: 'HOD', render: (r) => renderStars(r.hod_rating) },
    { key: 'final_rating', label: 'Final', render: (r) => renderStars(r.final_rating) },
    { key: 'actions', label: '', render: (r) =>
      r.status === 'hod_reviewed' ? (
        <Btn variant="success" size="xs" onClick={() => {
          setShowFinalize(r);
          setFinRating(r.final_rating || 0);
          setFinComments(r.hr_comments || '');
        }}>
          <Star size={13} /> Finalize
        </Btn>
      ) : null
    },
  ];

  return (
    <>
      <PageHeader
        title="Performance Management"
        subtitle="Set goals, track reviews and appraisal ratings"
        actions={
          <Btn onClick={() => setShowCreate(true)}>
            <Plus size={16} /> New Goal
          </Btn>
        }
      />

      {/* Bug #11 fix: c.is_active → c.status === 'active', c.name → c.title */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 16 }}>
        <h3 style={{ fontSize: 16, fontWeight: 600 }}>Appraisal Cycles</h3>
        {isHR && (
          <Btn size="sm" onClick={() => setShowCreateCycle(true)}>
            <Plus size={14} /> New Cycle
          </Btn>
        )}
      </div>
      <div className="grid-stats" style={{ marginBottom: 24 }}>
        {cycles.filter((c) => c.status === 'active').map((c) => (
          <Card key={c.id} style={{ padding: 16, borderLeft: '4px solid var(--primary)' }}>
            <div style={{ fontWeight: 600, fontSize: 15, marginBottom: 4 }}>{c.title}</div>
            <div style={{ fontSize: 13, color: 'var(--gray-500)' }}>
              {c.start_date} → {c.end_date}
            </div>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: 12 }}>
              <Badge variant="success">Active</Badge>
              {isHR && (
                <Btn variant="danger" size="xs" onClick={() => handleCloseCycle(c.id)}>
                  Close Cycle
                </Btn>
              )}
            </div>
          </Card>
        ))}
        {cycles.filter(c => c.status === 'active').length === 0 && <div style={{ color: 'var(--gray-500)', fontSize: 14 }}>No active cycles</div>}
      </div>

      <Card style={{ padding: 0, overflow: 'hidden' }}>
        <div style={{ padding: '16px 20px 0' }}>
          <Tabs tabs={tabs} active={tab} onChange={setTab} />
        </div>
        {tab === 'my' && <Table cols={myCols} rows={myGoals} loading={loading} emptyMsg="No goals found" />}
        {tab === 'hod' && (
          <>
            <div style={{ padding: '16px 20px', display: 'flex', justifyContent: 'flex-end', borderBottom: '1px solid var(--border-color)' }}>
              <Btn size="sm" onClick={() => setShowAssignGoal(true)}>
                <Plus size={14} /> Assign Goal to Team
              </Btn>
            </div>
            <Table cols={hodCols} rows={hodGoals} loading={loading} emptyMsg="No goals pending review" />
          </>
        )}
        {tab === 'all' && <Table cols={allCols} rows={allGoals} loading={loading} emptyMsg="No goals found" />}
      </Card>

      {/* Create Goal Modal — Bug #6 fix: uses goals_text */}
      <Modal open={showCreate} onClose={() => { setShowCreate(false); setAiSuggestion(''); }} title="Create Goal" width={480}>
        <form onSubmit={handleCreateGoal}>
          <Select
            label="Appraisal Cycle"
            value={goalForm.cycle_id}
            onChange={(e) => setGoalForm({ ...goalForm, cycle_id: e.target.value })}
            required
            id="goal-cycle"
          >
            <option value="">Select Cycle</option>
            {cycles.map((c) => (
              <option key={c.id} value={c.id}>{c.title}</option>
            ))}
          </Select>
          <Textarea
            label="Goal Description"
            value={goalForm.goals_text}
            onChange={(e) => setGoalForm({ ...goalForm, goals_text: e.target.value })}
            placeholder="Describe your goal objectives and key results"
            required
            id="goal-text"
          />
          <div style={{ margin: '12px 0' }}>
            <Btn type="button" variant="ghost" size="sm" onClick={handleEnhanceGoal} loading={aiLoading}>
              <span style={{ marginRight: 6 }}>✨</span> AI Suggest SMART Goal
            </Btn>
            {aiSuggestion && (
              <div style={{ padding: '12px 16px', background: 'var(--gray-50)', borderRadius: 8, marginTop: 12, fontSize: 13, border: '1px solid var(--border-color)', color: 'var(--text-light)', lineHeight: 1.6, whiteSpace: 'pre-wrap' }}>
                <div style={{ fontWeight: 600, marginBottom: 8, color: 'var(--text-dark)' }}>💡 AI Suggestion:</div>
                {aiSuggestion}
                <div style={{ display: 'flex', justifyContent: 'flex-end', marginTop: 12 }}>
                  <Btn size="xs" variant="outline" type="button" onClick={() => {
                    setGoalForm({ ...goalForm, goals_text: aiSuggestion });
                    setAiSuggestion('');
                  }}>
                    Use This Suggestion
                  </Btn>
                </div>
              </div>
            )}
          </div>
          <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 10, marginTop: 16 }}>
            <Btn variant="secondary" onClick={() => setShowCreate(false)} type="button">Cancel</Btn>
            <Btn type="submit" loading={submitting}>Save Goal</Btn>
          </div>
        </form>
      </Modal>

      {/* Self Review Modal — Bug #7 fix: self_comments */}
      <Modal open={!!showSelf} onClose={() => setShowSelf(null)} title="Self Review" width={440}>
        <form onSubmit={handleSelfReview}>
          <div style={{ marginBottom: 16 }}>
            <label style={{ display: 'block', fontSize: 13, fontWeight: 500, color: 'var(--text-light)', marginBottom: 8 }}>
              Your Rating
            </label>
            <StarRating value={selfRating} onChange={setSelfRating} size={28} />
          </div>
          <Textarea
            label="Comments"
            value={selfComments}
            onChange={(e) => setSelfComments(e.target.value)}
            placeholder="Describe your achievements and progress"
            id="self-comment"
          />
          <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 10, marginTop: 8 }}>
            <Btn variant="secondary" onClick={() => setShowSelf(null)}>Cancel</Btn>
            <Btn type="submit" loading={submitting}>Submit Review</Btn>
          </div>
        </form>
      </Modal>

      {/* HOD Review Modal — Bug #8 fix: hod_comments */}
      <Modal open={!!showHOD} onClose={() => setShowHOD(null)} title="HOD Review" width={440}>
        <form onSubmit={handleHODReview}>
          <div style={{ marginBottom: 16 }}>
            <label style={{ display: 'block', fontSize: 13, fontWeight: 500, color: 'var(--text-light)', marginBottom: 8 }}>
              HOD Rating
            </label>
            <StarRating value={hodRating} onChange={setHodRating} size={28} />
          </div>
          <Textarea
            label="Comments"
            value={hodComments}
            onChange={(e) => setHodComments(e.target.value)}
            placeholder="Provide feedback on the employee's performance"
            id="hod-comment"
          />
          <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 10, marginTop: 8 }}>
            <Btn variant="secondary" onClick={() => setShowHOD(null)}>Cancel</Btn>
            <Btn type="submit" loading={submitting}>Submit Review</Btn>
          </div>
        </form>
      </Modal>

      {/* HR Finalize Modal — Bug #9 fix: hr_comments */}
      <Modal open={!!showFinalize} onClose={() => setShowFinalize(null)} title="Finalize Rating" width={440}>
        <form onSubmit={handleFinalize}>
          <div style={{ marginBottom: 16 }}>
            <label style={{ display: 'block', fontSize: 13, fontWeight: 500, color: 'var(--text-light)', marginBottom: 8 }}>
              Final Rating
            </label>
            <StarRating value={finRating} onChange={setFinRating} size={28} />
          </div>
          <Textarea
            label="HR Comments"
            value={finComments}
            onChange={(e) => setFinComments(e.target.value)}
            placeholder="Final assessment comments"
            id="fin-comment"
          />
          <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 10, marginTop: 8 }}>
            <Btn variant="secondary" onClick={() => setShowFinalize(null)}>Cancel</Btn>
            <Btn type="submit" loading={submitting} variant="success">Finalize</Btn>
          </div>
        </form>
      </Modal>

      {/* Create Cycle Modal */}
      <Modal open={showCreateCycle} onClose={() => setShowCreateCycle(false)} title="Create Appraisal Cycle" width={480}>
        <form onSubmit={handleCreateCycle}>
          <Input label="Cycle Title" placeholder="e.g. Q1 2026 Performance" value={cycleForm.title} onChange={(e) => setCycleForm({ ...cycleForm, title: e.target.value })} required id="cycle-title" />
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '16px' }}>
            <Input label="Start Date" type="date" value={cycleForm.start_date} onChange={(e) => setCycleForm({ ...cycleForm, start_date: e.target.value })} required id="cycle-start" />
            <Input label="End Date" type="date" min={cycleForm.start_date} value={cycleForm.end_date} onChange={(e) => setCycleForm({ ...cycleForm, end_date: e.target.value })} required id="cycle-end" />
          </div>
          <Input label="Year" type="number" value={cycleForm.year} onChange={(e) => setCycleForm({ ...cycleForm, year: e.target.value })} required id="cycle-year" />
          <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 10, marginTop: 16 }}>
            <Btn variant="secondary" onClick={() => setShowCreateCycle(false)}>Cancel</Btn>
            <Btn type="submit" loading={submitting}>Create Cycle</Btn>
          </div>
        </form>
      </Modal>

      {/* Assign Goal Modal */}
      <Modal open={showAssignGoal} onClose={() => setShowAssignGoal(false)} title="Assign Goal to Team" width={480}>
        <form onSubmit={handleAssignGoal}>
          <Select label="Employee" value={assignForm.employee_id} onChange={(e) => setAssignForm({ ...assignForm, employee_id: e.target.value })} required id="assign-emp">
            <option value="">Select Employee</option>
            {teamMembers.map(emp => (
              <option key={emp.id} value={emp.id}>{emp.first_name} {emp.last_name}</option>
            ))}
          </Select>
          <Select label="Appraisal Cycle" value={assignForm.cycle_id} onChange={(e) => setAssignForm({ ...assignForm, cycle_id: e.target.value })} required id="assign-cycle">
            <option value="">Select Cycle</option>
            {cycles.filter(c => c.status === 'active').map(c => (
              <option key={c.id} value={c.id}>{c.title}</option>
            ))}
          </Select>
          <Textarea label="Goal Description" value={assignForm.goals_text} onChange={(e) => setAssignForm({ ...assignForm, goals_text: e.target.value })} placeholder="Describe the goal objectives" required id="assign-text" />
          <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 10, marginTop: 16 }}>
            <Btn variant="secondary" onClick={() => setShowAssignGoal(false)}>Cancel</Btn>
            <Btn type="submit" loading={submitting}>Assign Goal</Btn>
          </div>
        </form>
      </Modal>
    </>
  );
}
